import{_ as p,C as o,o as r,c as n,a1 as t,E as e,j as i,a as s}from"./chunks/framework.Clqesclh.js";const d="/images/202451/tianjin0.png",T=JSON.parse('{"title":"五一小长假（浙江台州 + 天津）","description":"","frontmatter":{"title":"五一小长假（浙江台州 + 天津）","date":"2024-05-27T02:01:23.000Z","recommend":false},"headers":[],"relativePath":"posts/taizhou_tianjin.md","filePath":"posts/taizhou_tianjin.md"}'),_={name:"posts/taizhou_tianjin.md"};function u(h,a,m,c,k,f){const l=o("ImageGallery");return r(),n("div",null,[a[0]||(a[0]=t('<p>五一期间去了浙江台（tāi）州和天津，去台州源于要见张信哲，后来发现国清寺真是个好地方，台州的小海鲜也很好吃，去天津原本是要 CityWalk，后来行程新增的国家海洋博物馆非常不错，很值得花上一整天参观。</p><h2 id="装包物品-26l背包" tabindex="-1">装包物品（26L背包） <a class="header-anchor" href="#装包物品-26l背包" aria-label="Permalink to &quot;装包物品（26L背包）&quot;">​</a></h2><ul><li>身份证、保温杯、充电宝、耳机、充电头和线、干湿纸巾、小零食、雨伞、洗漱物品、换洗衣物</li></ul><h2 id="推荐特色美食" tabindex="-1">推荐特色美食 <a class="header-anchor" href="#推荐特色美食" aria-label="Permalink to &quot;推荐特色美食&quot;">​</a></h2><ul><li>花雕鸡、手工青麻糍、醉蟹钳、拉尿虾、各种小海鲜、蛋清羊尾、松叶蟹、煎饼、炸糕</li></ul><h2 id="酒店及交通出行" tabindex="-1">酒店及交通出行 <a class="header-anchor" href="#酒店及交通出行" aria-label="Permalink to &quot;酒店及交通出行&quot;">​</a></h2><ul><li><p>住宿选景点附近或交通方便的位置，节假日一定要提前订</p></li><li><p>机票订完可能会降价，差价大的话可以考虑重新订</p></li><li><p>如果没有合适航班，可以考虑到附近城市，然后再转高铁</p></li><li><p>出门前查天气预报，再决定穿什么衣服和鞋，以及是否带伞</p></li></ul><h2 id="台州" tabindex="-1">台州 <a class="header-anchor" href="#台州" aria-label="Permalink to &quot;台州&quot;">​</a></h2><p>因为张信哲演唱会，才知道了浙江台州市，台州市旅游景点都分散在附近市县（天台县、仙居县、临海市等），各地相距大概几十公里，都各自有高铁站，交通比较方便。</p><p>行：直飞台州的航班被取消后，改成先飞到义乌，因抢不到高铁票，于是打车两小时到达天台县，出租司机在和他朋友聊天时，对方惊出“卧槽”</p><p>住：第一天住在临海市崇和门，离台州府城墙和人民路都比较近，第二天住台州市体育馆附近</p><p>吃：天台县土灶头饭店的花雕鸡、醉蟹钳和台州市和合大院的松叶蟹味道都很棒，临海市人民路上随便找家饭馆吃海鲜就行，味道都差不多，我们在第一家吃完后酒没喝完，于是换了一家继续喝，在这里还学会了唆螺</p><p>玩：国清寺 - 台州府城墙 - 张信哲演唱会 - 台州博物馆</p><ul><li><p>国清寺：建于隋代，有 1400 多年的历史，是中国佛教第一个宗派天台宗的发源地，现在是 5A 级景区，免费且不需要预约，也不售卖香火，一点也感觉不到商业气息，寺庙依山而筑，古树成荫，每个角落都有绿植覆盖，我们去的那天一直在下雨，游客不多，体验非常好，建议在这里安排三小时以上时间</p></li><li><p>台州府城墙：始建于东晋，经历代变革发展成现在的样子，明朝时戚继光在这里驻守抗倭，来这里游玩，可以先去东湖，然后从靠近揽胜门的出口出来，再由揽胜门上城墙，城墙大概有五公里长，可以在距终点不远的朝天门下来，进到古城内后走一会就到了紫阳街，街道很长，几乎都是卖小吃的</p></li><li><p>台州市体育场：打车从临海市到台州市，路上有点堵车，到体育场时张信哲正在唱第一首歌《信仰》，演唱会从 19:00 到 21:00，全程没有请嘉宾，就自己一直在唱，最后又加班半小时，以《爱如潮水》收尾，每一首歌都很好听，演唱会结束从体育场出来，我们骑共享电动车回酒店附近吃完很大的小龙虾后，便回去休息了</p></li><li><p>台州博物馆：台州市内没有什么特别的旅游景点，所以打算去台州博物馆看看，目前这里不用提前预约，但是关门比较早，馆内印象最深的就是“孝孺之死与台州式硬气”的介绍，今天再次坐到男哥电动车后排，虽然一半屁股在外面，但体验感超好，原以为两人就是这个单人共享电动车的极限，后来在另一车上发现有第三人蹲在前面</p></li></ul>',14)),e(l,{dir:"/images/202451/taizhou"}),a[1]||(a[1]=t('<h2 id="天津" tabindex="-1">天津 <a class="header-anchor" href="#天津" aria-label="Permalink to &quot;天津&quot;">​</a></h2><p>听男哥的话，选择坐高铁出行，原来从北京到天津玩，比从北京到北京玩还要方便，天津市区最适合的玩法就是 CityWalk，再加上国家海洋博物馆，两天时间足够了。</p><p>行：坐高铁去天津很方便，国家海洋博物馆在滨海，可以从天津站坐高铁到滨海站，然后再打车去，滨海站也有回北京南的车次</p><p>住：第二天要早起坐高铁去滨海，所以选择住在天津站附近</p><p>吃：晚上去利德诚撸串，味道还不错，有很多当地人也在这撸串喝酒，就是厕所条件差一些，门是坏的，我们在这喝啤酒喝到微醺，然后溜达了一会便回去睡觉了，第二天早上到滨海后，打车去老姑大早点店吃早点，味道还行</p><p>玩：市区 CityWalk - 国家海洋博物馆</p><ul><li><p>市区 CityWalk 路线（天津站 - 解放桥 - 津湾广场 - 小白楼 - 五大道 - 西开教堂 - 瓷房子 - 北安桥 - 金汤桥 - 狮子林桥（看大爷跳水） - 金刚桥（看天津之眼））：可以按这个路线去走，我们沿途还参观了计划外的两个博物馆，天津邮政博物馆和天津体育博物馆，都不需要预约，凭身份证就可以进入，孩子们还在这里盖章和买纪念币，我们沿计划路线走了一天，吃完晚饭走到北安桥时已经十一点多，便回酒店睡觉休息了</p></li><li><p>国家海洋博物馆：目前是世界规模最大的海洋博物馆，展示了人类探索海洋的历史和海洋与生命的演化历程，非常值得花上一整天去参观，记得提前一周在公众号上预约门票，如果没约上，可以购买博物馆内的收费场馆的票然后再进主馆。</p></li></ul>',7)),e(l,{dir:"/images/202451/tianjin"}),a[2]||(a[2]=i("h2",{id:"天津市区-citywalk-路线",tabindex:"-1"},[s("天津市区 CityWalk 路线 "),i("a",{class:"header-anchor",href:"#天津市区-citywalk-路线","aria-label":'Permalink to "天津市区 CityWalk 路线"'},"​")],-1)),a[3]||(a[3]=i("p",null,[i("img",{src:d,alt:"天津市区 CityWalk 路线",title:"天津市区 CityWalk 路线"})],-1))])}const b=p(_,[["render",u]]);export{T as __pageData,b as default};
